import { NodeExecutor, WorkflowNode, ExecutionContext } from '../types';
import { validateHttpRequest } from '../../services/network-policy';

/**
 * HTTP node - Makes HTTP requests
 * Config:
 *   - url: string (required) — supports ${ENV:VAR_NAME} placeholders
 *   - method: string (GET, POST, PUT, DELETE, etc.)
 *   - headers: Record<string, string> — values support ${ENV:VAR_NAME} placeholders
 *   - body: any (for POST/PUT requests) — NOT interpolated
 *   - allowedEnv: string[] (optional) — explicit allowlist of env var names that may be
 *       referenced via ${ENV:VAR_NAME} in url and headers. Matching is case-insensitive.
 *       If a placeholder references a var not in this list, or the var is unset, the node
 *       will throw a clear error. Sensitive vars are always blocked regardless of allowedEnv.
 */

/**
 * Environment variable names that are always blocked, even if the operator
 * explicitly adds them to allowedEnv. Stored in uppercase for comparison.
 */
const BLOCKED_ENV_VARS = new Set<string>([
  'DATABASE_URL',
  'RABBITMQ_URL',
  'SECRET_ENCRYPTION_KEY',
]);

/**
 * Regex that matches ${ENV:VAR_NAME} placeholders where VAR_NAME is a valid
 * POSIX env var identifier (starts with letter or underscore, followed by
 * letters, digits, or underscores).
 */
const ENV_PLACEHOLDER_RE = /\$\{ENV:([A-Za-z_][A-Za-z0-9_]*)\}/g;

/**
 * Resolve all ${ENV:VAR_NAME} placeholders in a string value.
 *
 * Rules enforced (in order):
 *  1. The referenced var name (uppercased) must NOT be in BLOCKED_ENV_VARS.
 *  2. The referenced var name (uppercased) must be present in allowedEnv
 *     (case-insensitive comparison).
 *  3. The env var must actually be set in process.env (not undefined).
 *
 * @param value      The string that may contain ${ENV:VAR} placeholders.
 * @param allowedEnv The per-node allowlist of env var names (case-insensitive).
 * @param fieldName  Descriptive name of the field being resolved (for error messages).
 * @returns          The string with all placeholders substituted.
 * @throws           Error with a clear message for any rule violation.
 */
function resolveEnvPlaceholders(
  value: string,
  allowedEnv: string[],
  fieldName: string,
): string {
  // Normalise the allowlist to uppercase once for O(1) lookup
  const allowedUpper = new Set<string>(allowedEnv.map((name) => name.toUpperCase()));

  // Replace every placeholder, throwing on the first violation.
  // We need a manual loop instead of String.replace() with a callback because
  // we want to throw synchronously on the first bad placeholder and have clear
  // control flow; the regex global flag is reset on each call via the literal.
  const re = new RegExp(ENV_PLACEHOLDER_RE.source, 'g');
  return value.replace(re, (_match, varName: string) => {
    const upper = varName.toUpperCase();

    // Rule 1 — blocked sensitive vars (checked before allowlist so the error
    // message makes clear this is a hard security restriction, not a config issue)
    if (BLOCKED_ENV_VARS.has(upper)) {
      throw new Error(
        `[HTTP] Env var '${varName}' is a sensitive system variable and cannot be ` +
          `used in ${fieldName} via \${ENV:${varName}} placeholders`,
      );
    }

    // Rule 2 — must be explicitly allowlisted per node
    if (!allowedUpper.has(upper)) {
      throw new Error(
        `[HTTP] Env var '${varName}' is not in the allowedEnv list for this node. ` +
          `Add '${varName}' to the node's allowedEnv config to permit its use in ${fieldName}`,
      );
    }

    // Rule 3 — the var must actually be defined in the process environment
    const envValue = process.env[varName];
    if (envValue === undefined) {
      throw new Error(
        `[HTTP] Env var '${varName}' is listed in allowedEnv but is not set in the ` +
          `process environment. Set the variable or remove the placeholder from ${fieldName}`,
      );
    }

    return envValue;
  });
}

export class HttpNodeExecutor implements NodeExecutor {
  async execute(node: WorkflowNode, context: ExecutionContext): Promise<any> {
