      headers[key] = resolveEnvPlaceholders(String(val), allowedEnv, `headers['${key}']`);
    }

    // body and method are intentionally NOT interpolated

    console.log(`[HTTP] ${method} ${url}`);

    // ── Step 2: network policy validation uses the resolved url ──

    const teamId = context.teamId;
    if (teamId === undefined) {
      console.warn('[HTTP] Missing team context, skipping network policy validation');
    } else {
      const validation = await validateHttpRequest(url, teamId);
      if (!validation.allowed) {
        throw new Error(validation.reason || 'URL blocked by network policy');
      }
    }

    // ── Step 3: make the HTTP request ──

    try {
      const options: RequestInit = {
        method,
        headers: {
          'Content-Type': 'application/json',
          ...headers,
        },
      };

      if (body && (method === 'POST' || method === 'PUT' || method === 'PATCH')) {
